import React, { useState, useEffect, useRef } from 'react';
import './CircularGallery.css';

export default function CircularGallery({ items }) {
  const [angle, setAngle] = useState(0);
  const [targetAngle, setTargetAngle] = useState(0);
  const [hoveredIndex, setHoveredIndex] = useState(null);
  const animRef = useRef(null);
  const isDragging = useRef(false);
  const lastX = useRef(0);

  const count = items.length;
  const step = 360 / count;

  // Smooth lerp animation
  useEffect(() => {
    const animate = () => {
      setAngle(prev => {
        const diff = targetAngle - prev;
        if (Math.abs(diff) < 0.01) return targetAngle;
        return prev + diff * 0.08;
      });
      animRef.current = requestAnimationFrame(animate);
    };
    animRef.current = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(animRef.current);
  }, [targetAngle]);

  const rotate = (dir) => {
    setTargetAngle(prev => prev + dir * step);
  };

  const onMouseDown = (e) => {
    isDragging.current = true;
    lastX.current = e.clientX;
  };
  const onMouseMove = (e) => {
    if (!isDragging.current) return;
    const delta = e.clientX - lastX.current;
    lastX.current = e.clientX;
    setTargetAngle(prev => prev - delta * 0.4);
  };
  const onMouseUp = () => { isDragging.current = false; };

  const onTouchStart = (e) => {
    isDragging.current = true;
    lastX.current = e.touches[0].clientX;
  };
  const onTouchMove = (e) => {
    if (!isDragging.current) return;
    const delta = e.touches[0].clientX - lastX.current;
    lastX.current = e.touches[0].clientX;
    setTargetAngle(prev => prev - delta * 0.4);
  };
  const onTouchEnd = () => { isDragging.current = false; };

  return (
    <div className="cg-root">
      <button className="cg-arrow cg-left" onClick={() => rotate(1)}>‹</button>

      <div
        className="cg-scene"
        onMouseDown={onMouseDown}
        onMouseMove={onMouseMove}
        onMouseUp={onMouseUp}
        onMouseLeave={onMouseUp}
        onTouchStart={onTouchStart}
        onTouchMove={onTouchMove}
        onTouchEnd={onTouchEnd}
      >
        <div className="cg-carousel" style={{ '--count': count }}>
          {items.map((item, i) => {
            const itemAngle = angle + i * step;
            const rad = (itemAngle * Math.PI) / 180;
            const radius = 420;
            const x = Math.sin(rad) * radius;
            const z = Math.cos(rad) * radius;
            const scale = (z + radius) / (radius * 2);
            const scaleMapped = 0.55 + scale * 0.65;
            const opacity = 0.3 + scale * 0.7;
            const zIndex = Math.round(scale * 100);
            const isHovered = hoveredIndex === i;

            return (
              <div
                key={i}
                className="cg-card"
                style={{
                  transform: `translateX(${x}px) scale(${isHovered ? scaleMapped * 1.06 : scaleMapped})`,
                  opacity,
                  zIndex,
                  transition: 'transform 0.2s ease, opacity 0.2s ease',
                }}
                onMouseEnter={() => setHoveredIndex(i)}
                onMouseLeave={() => setHoveredIndex(null)}
              >
                <img src={item.image} alt={item.org} />
                <div className={`cg-overlay ${isHovered ? 'visible' : ''}`}>
                  <div className="cg-org">{item.org}</div>
                  <div className="cg-divider" />
                  <div className="cg-roles">
                    {item.roles.map((r) => <span key={r}>{r}</span>)}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      <button className="cg-arrow cg-right" onClick={() => rotate(-1)}>›</button>
    </div>
  );
}
